  // ──────────────────────────────────────────────────
  // Internal request helper
  // ──────────────────────────────────────────────────

  Future<dynamic> _request(
    String method,
    String path, {
    Map<String, dynamic>? body,
    String? token,
  }) async {
    final uri = Uri.parse('$_baseUrl$path');
    final headers = <String, String>{
      ..._defaultHeaders,
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    };

    if (token != null) {
      headers['Authorization'] = 'Bearer $token';
    }

    final encodedBody = body != null ? jsonEncode(body) : null;
    late http.Response response;

    switch (method) {
      case 'GET':
        response = await _httpClient.get(uri, headers: headers);
      case 'POST':
        response = await _httpClient.post(uri, headers: headers, body: encodedBody);
      case 'PUT':
        response = await _httpClient.put(uri, headers: headers, body: encodedBody);
      case 'PATCH':
        response = await _httpClient.patch(uri, headers: headers, body: encodedBody);
      case 'DELETE':
        response = await _httpClient.delete(uri, headers: headers, body: encodedBody);
      default:
        throw AuthClientException('Unsupported HTTP method: $method');
    }

    if (response.statusCode < 200 || response.statusCode >= 300) {
      String errorMessage;
      int? errorCode;
      try {
        final errorBody = jsonDecode(response.body) as Map<String, dynamic>;
        errorMessage = (errorBody['error'] as String?) ??
            'Request failed with status ${response.statusCode}';
        errorCode = (errorBody['code'] as int?) ?? response.statusCode;
      } catch (_) {
        errorMessage = 'Request failed with status ${response.statusCode}';
        errorCode = response.statusCode;
      }
      throw AuthClientException(errorMessage, code: errorCode);
    }

    if (response.statusCode == 204 || response.body.isEmpty) {
      return null;
    }

    return jsonDecode(response.body);
  }

  // ──────────────────────────────────────────────────
  // OAuth2 Device Authorization (RFC 8628)
  // ──────────────────────────────────────────────────

  /// Start device authorization flow.
  /// POST /v1/oauth/device/authorize
  Future<DeviceAuthorizationResponse> deviceAuthorize({
    required DeviceAuthorizationRequest body,
  }) async {
    const path = '/v1/oauth/device/authorize';
    final res = await _request('POST', path, body: body.toJson());
    return DeviceAuthorizationResponse.fromJson(
        Map<String, dynamic>.from(res as Map));
  }

  /// Poll for device token (called repeatedly by CLI).
  /// POST /v1/oauth/device/token
  ///
  /// Returns [DeviceTokenResponse] on success.
  /// Throws [DeviceTokenPendingException] when authorization is pending.
  /// Throws [DeviceTokenSlowDownException] when polling too fast.
  /// Throws [AuthClientException] for other errors.
  Future<DeviceTokenResponse> deviceToken({
    required DeviceTokenRequest body,
  }) async {
    const path = '/v1/oauth/device/token';
    final uri = Uri.parse('$_baseUrl$path');
    final headers = <String, String>{
      ..._defaultHeaders,
      'Content-Type': 'application/json',
      'Accept': 'application/json',
    };

    final response = await _httpClient.post(
      uri,
      headers: headers,
      body: jsonEncode(body.toJson()),
    );

    final responseBody = jsonDecode(response.body) as Map<String, dynamic>;

    if (response.statusCode >= 200 && response.statusCode < 300) {
      return DeviceTokenResponse.fromJson(responseBody);
    }

    // Handle RFC 8628 error responses
    final error = DeviceTokenError.fromJson(responseBody);
    if (error.isPending) {
      throw DeviceTokenPendingException();
    }
    if (error.isSlowDown) {
      throw DeviceTokenSlowDownException();
    }
    if (error.isExpired) {
      throw DeviceTokenExpiredException();
    }
    if (error.isAccessDenied) {
      throw DeviceTokenDeniedException();
    }

    throw AuthClientException(
      error.errorDescription ?? error.error,
      code: response.statusCode,
    );
  }

  /// Complete device authorization (user approves/denies from web UI).
  /// POST /v1/oauth/device/complete
  Future<DeviceCompleteResponse> deviceComplete({
    required DeviceCompleteRequest body,
    required String token,
  }) async {
    const path = '/v1/oauth/device/complete';
    final res = await _request('POST', path, body: body.toJson(), token: token);
    return DeviceCompleteResponse.fromJson(
        Map<String, dynamic>.from(res as Map));
  }

  /// Fetch OIDC discovery document.
  /// GET /.well-known/openid-configuration
  Future<OidcDiscoveryDocument> getOidcDiscovery() async {
    const path = '/.well-known/openid-configuration';
    final res = await _request('GET', path);
    return OidcDiscoveryDocument.fromJson(
        Map<String, dynamic>.from(res as Map));
  }

  /// Fetch OIDC UserInfo.
  /// GET /v1/oauth/userinfo
  Future<OidcUserInfoResponse> getOidcUserInfo({required String token}) async {
    const path = '/v1/oauth/userinfo';
    final res = await _request('GET', path, token: token);
    return OidcUserInfoResponse.fromJson(
        Map<String, dynamic>.from(res as Map));
  }
}

/// Thrown when device token endpoint returns `authorization_pending`.
class DeviceTokenPendingException implements Exception {
  @override
  String toString() => 'DeviceTokenPendingException: authorization_pending';
}

/// Thrown when device token endpoint returns `slow_down`.
class DeviceTokenSlowDownException implements Exception {
  @override
  String toString() => 'DeviceTokenSlowDownException: slow_down';
}

/// Thrown when device token endpoint returns `expired_token`.
class DeviceTokenExpiredException implements Exception {
  @override
  String toString() => 'DeviceTokenExpiredException: expired_token';
}

/// Thrown when device token endpoint returns `access_denied`.
class DeviceTokenDeniedException implements Exception {
  @override
  String toString() => 'DeviceTokenDeniedException: access_denied';
}

/// Exception thrown by the AuthSome API client.
class AuthClientException implements Exception {
  final String message;
  final int? code;

  const AuthClientException(this.message, {this.code});

  @override
  String toString() => 'AuthClientException($code): $message';
}
